const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  return {
    isDark,
    bg: isDark ? "#09090b" : "#fafafa",
    surface: isDark ? "#18181b" : "#f4f4f5",
    text: isDark ? "#fafafa" : "#09090b",
    muted: isDark ? "#a1a1aa" : "#71717a",
    subtle: isDark ? "#52525b" : "#a1a1aa",
    accent: isDark ? "#10b981" : "#059669", // Emerald
    accentSoft: isDark ? "#064e3b" : "#dcfce7",
    warning: isDark ? "#f59e0b" : "#d97706", // Amber
    error: isDark ? "#ef4444" : "#dc2626", // Red
    border: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)",
    grid: isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.03)",
    glowPrimary: isDark ? "rgba(16,185,129,0.12)" : "rgba(16,185,129,0.08)",
    glowSecondary: isDark ? "rgba(245,158,11,0.08)" : "rgba(245,158,11,0.05)",
  };
}

const CARD = { width: 1200, height: 630 };

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  roundRect(ctx, x, y, w, h, r);
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function drawGrid(ctx, w, h, color) {
  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  const size = 40;
  for (let x = 0; x <= w; x += size) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, h);
    ctx.stroke();
  }
  for (let y = 0; y <= h; y += size) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(w, y);
    ctx.stroke();
  }
  ctx.restore();
}

function drawGlow(ctx, x, y, radius, color, w, h) {
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
  gradient.addColorStop(0, color);
  gradient.addColorStop(1, "transparent");
  ctx.save();
  ctx.globalCompositeOperation = "screen";
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, w, h);
  ctx.restore();
}

function drawLabel(ctx, text, x, y, color) {
  ctx.font = `800 11px ${MONO}`;
  ctx.fillStyle = color;
  ctx.fillText(String(text || "").toUpperCase(), x, y);
}

function getAccuracyStyle(label, t) {
  const styles = {
    Trustworthy: { color: t.accent, bg: t.accent + "1A", border: t.accent + "33" },
    Suspicious: { color: t.warning, bg: t.warning + "1A", border: t.warning + "33" },
    Flagged: { color: t.error, bg: t.error + "1A", border: t.error + "33" },
    Neutral: { color: t.subtle, bg: t.surface, border: t.border },
  };
  return styles[label] || styles.Neutral;
}

export async function renderSellerCardToBlob(seller) {
  const { name, totalListings, validListings, avgMarkupPercent, overpricedRatio, accuracyLabel, isBlacklisted } = seller || {};
  const t = themeColors();
  const v = CARD;
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = v.width;
    canvas.height = v.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas is unavailable")); return; }

    ctx.fillStyle = t.bg;
    ctx.fillRect(0, 0, v.width, v.height);
    
    // Background glows
    drawGlow(ctx, v.width - 200, 100, 600, t.glowPrimary, v.width, v.height);
    drawGlow(ctx, 100, v.height - 100, 500, t.glowSecondary, v.width, v.height);
    
    drawGrid(ctx, v.width, v.height, t.grid);

    // Header
    ctx.save();
    ctx.font = `900 12px ${MONO}`;
    ctx.fillStyle = t.accent;
    ctx.beginPath();
    ctx.arc(62, 46, 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillText("CMI SELLER", 74, 50);
    
    ctx.fillStyle = t.subtle;
    ctx.textAlign = "right";
    ctx.font = `700 11px ${MONO}`;
    ctx.fillText(new Date().toUTCString().slice(5, 16).toUpperCase(), v.width - 56, 50);
    ctx.restore();

    // Seller name
    ctx.font = `900 58px ${SANS}`;
    ctx.fillStyle = t.text;
    ctx.letterSpacing = "-0.02em";
    const nameDisplay = name || "Unknown Seller";
    ctx.fillText(nameDisplay.length > 20 ? nameDisplay.slice(0, 18) + "..." : nameDisplay, 56, 135);
    ctx.letterSpacing = "normal";

    // Accuracy badge
    const badge = getAccuracyStyle(accuracyLabel, t);
    const label = (accuracyLabel || "Neutral").toUpperCase();
    ctx.font = `900 14px ${MONO}`;
    ctx.fillStyle = badge.color;
    fillRoundRect(ctx, v.width - 200, 100, 144, 34, 6, badge.bg, badge.border);
    ctx.textAlign = "center";
    ctx.fillText(label, v.width - 200 + 72, 122);
    ctx.textAlign = "left";

    // Stats grid
    const contentX = 56;
    const contentY = 200;
    const contentWidth = v.width - contentX * 2;
    const gutter = 24;
    const boxW = (contentWidth - gutter) / 2;

    function drawStatBox(labelText, value, x, y, note = "") {
      fillRoundRect(ctx, x, y, boxW, 120, 12, t.surface, t.border);
      ctx.font = `800 11px ${MONO}`;
      ctx.fillStyle = t.muted;
      ctx.fillText(labelText.toUpperCase(), x + 20, y + 28);
      
      ctx.font = `900 42px ${MONO}`;
      ctx.fillStyle = t.text;
      ctx.fillText(value, x + 20, y + 74);
      
      if (note) {
        ctx.font = `700 10px ${MONO}`;
        ctx.fillStyle = t.subtle;
        ctx.fillText(note.toUpperCase(), x + 20, y + 102);
      }
    }

    drawStatBox("Total Listings", String(totalListings || "0"), contentX, contentY, "Lifetime recorded");
    drawStatBox("Active Listings", String(validListings || "0"), contentX + boxW + gutter, contentY, "Live in market");
    drawStatBox("Avg. Markup", fmtPercent(avgMarkupPercent), contentX, contentY + 144, "Deviation from median");
    drawStatBox("Overpriced", fmtPercent(overpricedRatio, true), contentX + boxW + gutter, contentY + 144, "> 110% of median");

    // Risk indicator
    const riskY = contentY + 310;
    drawLabel(ctx, "Market integrity profile", contentX, riskY, t.muted);

    const riskBarY = riskY + 24;
    const riskBarWidth = contentWidth;
    const riskVal = Math.min(1, Math.max(0, ((avgMarkupPercent || 0) + 20) / 100));
    const riskColor = riskVal > 0.6 ? t.error : riskVal > 0.3 ? t.warning : t.accent;
    
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth, 16, 4, t.surface, t.border);
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth * riskVal, 16, 4, riskColor + "33", riskColor);

    ctx.font = `700 10px ${MONO}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText("LOWER MARKUP INDICATES BETTER VALUE FOR BUYERS", contentX, riskBarY + 36);

    // Status Footer
    const footerY = v.height - 30;
    ctx.font = `800 10px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("CASTIA MARKET INSIGHT", 56, footerY);
    
    ctx.textAlign = "right";
    ctx.fillStyle = t.subtle;
    ctx.fillText("DATA AGGREGATED BY LEKTO_", v.width - 56, footerY);
    
    if (isBlacklisted) {
      ctx.fillStyle = t.error;
      ctx.fillText("RESTRICTED TRADER", v.width - 56, footerY - 18);
    }
    ctx.restore();

    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG export failed"));
    }, "image/png");
  });
}

function fmtPercent(n, isFraction = false) {
  if (n == null) return "—";
  const val = isFraction ? n * 100 : n;
  return `${val >= 0 ? "+" : ""}${val.toFixed(1)}%`;
}

export async function downloadSellerCard(seller) {
  const blob = await renderSellerCardToBlob(seller);
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(seller.name || "seller").replace(/\s+/g, "-")}-trading-card.png`;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
